  }
}

{
  "role": "assistant",
  "content": [
    {
      "type": "text",
      "text": "I need to check the stock price for AAPL."
    },
    {
      "type": "tool_use",
      "id": "toolu_01A12v3xX",
      "name": "get_stock_price",
      "input": { "symbol": "AAPL" }
    }
  ],
  "stop_reason": "tool_use"
}

switch (response.stop_reason) {
  case "tool_use":
    // Claude requested tool execution → execute tools → send results back
    break;
  case "end_turn":
    // Claude completed response → conversation can continue
    break;
  case "max_tokens":
    // Claude reached token limit → may have more to say
    break;
  case "stop_sequence":
    // Claude encountered predefined stop sequence
    break;
}

const tools = [
  {
    name: "get_stock_price",
    description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices.",
    input_schema: {
      type: "object",
      properties: {
        symbol: {
          type: "string",
          description: "Stock symbol (e.g., 'AAPL' for Apple)"
        }
      },
      required: ["symbol"]
    }
  }
];

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    {
      role: "user",
      content: "What's the stock price for AAPL?"
    }
  ],
  tools: tools,
  tool_choice: { type: "auto" } // Default: Claude decides when to call
});

// When stop_reason == "tool_use"
if (response.stop_reason === "tool_use") {
  // Extract tool_use blocks from content
  const toolUseBlocks = response.content.filter(c => c.type === "tool_use");

  console.log("Number of tool calls:", toolUseBlocks.length);

  // Extract: name, input, id for each
  toolUseBlocks.forEach(block => {
    console.log("Tool name:", block.name);
    console.log("Tool input:", block.input);
    console.log("Tool ID:", block.id);
  });
}

// Your app executes the tool
function executeTool(toolName, toolInput) {
  switch (toolName) {
    case "get_stock_price":
      return getStockPrice(toolInput.symbol);
    case "query_database":
      return queryDatabase(toolInput.query);
    default:
      throw new Error(`Unknown tool: ${toolName}`);
  }
}

// Execute each tool
const toolExecutions = toolUseBlocks.map(block => {
  const result = executeTool(block.name, block.input);
  return { toolUseId: block.id, result: result };
});

// Create tool_result blocks
const toolResultBlocks = toolExecutions.map(exec => ({
  type: "tool_result",
  tool_use_id: exec.toolUseId,
  content: exec.result.toString()
}));

// Send back to Claude
const response2 = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    ...response.messages,
    {
      role: "user",
      content: toolResultBlocks
    }
  ],
  tools: tools
});

// Claude continues reasoning with result
console.log(response2.content[0].text);
// "AAPL is currently trading at $175.43"

// Claude requests multiple tools in one turn
const toolUseBlocks = response.content.filter(c => c.type === "tool_use");

// Execute in parallel
const results = await Promise.all(
  toolUseBlocks.map(block => executeTool(block.name, block.input))
);

// Send back all results
const toolResultBlocks = toolUseBlocks.map((block, i) => ({
  type: "tool_result",
  tool_use_id: block.id,
  content: results[i].toString()
}));

